#include<bits/stdc++.h>
using namespace std;
int main() {
	int a[201][201] = {0}, b[201][201] = {0}, l, r, c[201][201] = {0};
	int n;

	cin >> n;
	int maxx = -99999999;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cin >> a[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			b[i][j] = b[i][j - 1] + a[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			c[i][j] = c[i - 1][j] + b[i][j];
		}
	}
	for (int ax = 0; ax <= n; ax++) {
		for (int ay = 0; ay <= n; ay++) {
			for (int bx = ax; bx <= n; bx++) {
				for (int by = ay; by <= n; by++) {
					maxx = max(maxx, c[bx][by] - c[ax][by] - c[bx][ay] + c[ax][ay]);
				}
			}
		}
	}cout<<maxx;
	return 0;
}
